// Helper: get unique collections
export const collections = [...new Set(products.map(p => p.collection))].sort()

// Helper: get unique formats
export const formats = [...new Set(products.map(p => p.format))].sort()

// Helper: get unique colors
export const colors = [...new Set(products.map(p => p.color))].filter(Boolean).sort()

// Helper: get products by collection
export function getProductsByCollection(collection: string): Product[] {
  return products.filter(p => p.collection === collection)
}

// Helper: get product by id or slug
export function getProduct(idOrSlug: string): Product | undefined {
  return products.find(p => p.id === idOrSlug || p.slug === idOrSlug)
}
